3	export function claimOffice(request: any): any {
4	  const item = request.steps[0].items[0];
5	  const basePremiums: Record<string, number> = {
6	    sword: 100,
7	    amulet: 60,
8	    staff: 80,
9	  };
10	  const base = basePremiums[item.type];
11	  return [{ premium: base + PROCESSING_FEE }];
12	}
